"use strict";const headerBurger=document.querySelector(".header__burger"),body=document.querySelector("body"),headerContent=document.querySelector(".header__content"),mobMenuClose=document.querySelector(".mob-menu-close");headerBurger.addEventListener("click",(()=>{window.innerWidth<992&&(body.classList.add("lock"),headerContent.classList.add("open"))})),mobMenuClose.addEventListener("click",(()=>{body.classList.remove("lock"),headerContent.classList.remove("open")}));